MERGE INTO  NMCP_CD_DTL
USING 		DUAL
ON         (DTL_CD = #{dtlCd}
            AND CD_GROUP_ID =#{cdGroupId} )
WHEN MATCHED THEN
        UPDATE SET
                    DTL_CD_NM = #{dtlCdNm}
                    , INDC_ODRG = #{indcOdrg}
                    , USE_YN = #{useYN}
                    , EXPNSN_STR_VAL1 = #{expandStrOne}
                    , EXPNSN_STR_VAL2 = #{expandStrTwo}
                    , EXPNSN_STR_VAL3 = #{expandStrThree}
                    , DTL_CD_DESC = #{dtlCdDesc}
                    , AMD_ID = #{amdId}
                    , AMD_DT = SYSDATE
WHEN NOT MATCHED THEN
    INSERT    (
                    CD_GROUP_ID
                    , DTL_CD
                    , DTL_CD_NM
                    , INDC_ODRG
                    , USE_YN
                    , EXPNSN_STR_VAL1
                    , EXPNSN_STR_VAL2
                    , EXPNSN_STR_VAL3
                    , DTL_CD_DESC
                    , CRET_ID
                    , CRET_DT
        )
    VALUES    (
                    #{cdGroupId}
                    , #{dtlCd}
                    , #{dtlCdNm}
                    , #{indcOdrg}
                    , #{useYN}
                    , #{expandStrOne}
                    , #{expandStrTwo}
                    , #{expandStrThree}
                    , #{dtlCdDesc}
                    , #{cretId}
                    , SYSDATE
        )

mapper.select:
SELECT DTL_CD_NM FROM NMCP_CD_DTL
WHERE 1=1
    AND CD_GROUP_ID = #{cdGroupId}
    AND DTL_CD = #{dtlCd}

SELECT /*CommCodeMapper.listLinkInfo 고객포탈 링크 정보 */ LINK_ID ,LINK_NM ,LINK_URL ,LINK_DESC ,LINK_TYPE ,CRET_ID ,AMD_ID ,CRET_DT ,AMT_DT FROM NMCP_LINK_INFO WHERE 1=1
AND LINK_ID = #{linkId}
ORDER BY CRET_DT DESC

