UPDATE /*CommCodeMapper.updateLinkInfo 고객포탈 링크 정보  수정   */
    NMCP_LINK_INFO
SET
     AMD_ID = #{cretId}
     , AMT_DT = SYSDATE
     , LINK_NM = #{linkNm}
    , LINK_URL = #{linkUrl}
    , LINK_DESC = #{linkDesc} 
    , LINK_TYPE = #{linkType} 
WHERE
    LINK_ID = #{linkId}
